class Dog:
    def bark(self):
        print('Woof!')

my_dog = Dog()
my_dog.bark()

class Dog:
    def __init__(self, name):
        self.name = name

    def bark(self):
        print(f'{self.name} says Woof!')

my_dog = Dog('Rex')
my_dog.bark()

class Dog:
    def __init__(self, name, age):
        self.name = name
        self.age = age

    def bark(self):
        print(f'{self.name} says Woof!')

    def birthday(self):
        self.age += 1
        print(f'{self.name} is now {self.age} years old!')

my_dog = Dog('Rex', 3)
my_dog.bark()
my_dog.birthday()

